def caesar_cipher(text: str, shift: int) -> str:
    result = []

    for char in text:
        if 'a' <= char <= 'z':
            # Handle lowercase letters
            offset = ord('a')
            shifted = (ord(char) - offset + shift) % 26
            result.append(chr(offset + shifted))
        elif 'A' <= char <= 'Z':
            # Handle uppercase letters
            offset = ord('A')
            shifted = (ord(char) - offset + shift) % 26
            result.append(chr(offset + shifted))
        else:
            # Leave non-alphabetic characters unchanged
            result.append(char)

    return ''.join(result)

